scwin.onpageload = function () {
  scwin.params = $c.data.getParameter($p);
  console.log("#### 21p scwin.params : " + Object.keys(scwin.params).length + "<<< #### >>>" + JSON.stringify(scwin.params));

  //공통코드 적용()
  const codeOptions = [{
    grpCd: "OP678",
    compID: "lc_hndlCdOut,lc_hndlCdIn"
  } //F/E
  ];
  $c.data.setCommonCode($p, codeOptions);

  //DsConstants.CRRYINOUT_EDI_COPI_CODECO (COPI_CODECO) = CD / (COPINO) = CO
  scwin.crryoutEdiType = scwin.params.crryoutEdiType;
  scwin.crryinEdiType = scwin.params.crryinEdiType;

  //반출(COPINO)
  if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryoutEdiType) {
    tb_crryOutCopinoAll.show("none");
  } else {
    tb_crryOutCopinoAll.show("inline");
    grp_crryCopiCodeco.hide();
  }

  //반출(COPI_CODECO)
  if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryoutEdiType) {
    tb_crryOutCopiCodecoAll.show("inline");
  } else {
    tb_crryOutCopiCodecoAll.show("none");
  }

  //반입(COPINO)
  if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryinEdiType) {
    tb_crryInCopinoAll.hide();
  } else {
    tb_crryInCopinoAll.show();
    grp_crryCopiCodeco.hide();
  }

  //반입(COPI_CODECO)
  if (DsConstants.CRRYINOUT_EDI_COPI_CODECO == scwin.crryinEdiType) {
    tb_crryInCopiCodecoAll.show("inline");
  } else {
    tb_crryInCopiCodecoAll.show("none");
  }
  if (Object.keys(scwin.params).length > 0) {
    em_odrNo.setValue(scwin.params.arrParam[0][2]);
    em_wrkStDt.setValue(scwin.params.arrParam[0][9]);
    em_wrkEndDt.setValue(scwin.params.arrParam[0][10]);
    em_cntrNo.setValue(scwin.params.arrParam[0][11]);
    em_dptWrkPlCd.setValue(scwin.params.arrParam[0][12]);
    em_arvWrkPlCd.setValue(scwin.params.arrParam[0][13]);
    txt_dptWrkPlNm.setValue(scwin.params.arrParam[0][14]);
    txt_arvWrkPlNm.setValue(scwin.params.arrParam[0][15]);
    scwin.gv_crryoutEdiType = scwin.params.arrParam[0][16];
    scwin.gv_crryinEdiType = scwin.params.arrParam[0][17];
    scwin.param_gubun = scwin.params.arrParam[0][18];
    scwin.f_Retrieve();
  } else {
    $c.win.alert($p, "EDI정보를 가져오지 못했습니다");
    return false;
  }
  $c.gus.cfDisableObjects($p, [tb_srchCond]);
  if (scwin.loginId == "001249" || scwin.loginId == "021270" || scwin.loginId == "030428" || scwin.loginId == "100423" || scwin.loginId == "140814" || scwin.loginId == "zampion" || scwin.loginId == "areum") {
    $c.gus.cfDisableObjects($p, [chk_bondTransYn, ed_bondYardCd, txt_bondYardNm]);
  }
  if (scwin.userClsCd == "05") {
    $c.gus.cfDisableObjects($p, [lc_bondTransVehclYn1, lc_bondTransVehclYn2]);
  }
};

