scwin.f_Retrieve = function () {
  dma_search.set("qryClsCd", scwin.params.arrParam[0][0]);
  dma_search.set("transWrkIndictNo", scwin.params.arrParam[0][1]);
  dma_search.set("odrNo", scwin.params.arrParam[0][2]);
  dma_search.set("cntrSeq", scwin.params.arrParam[0][3]);
  dma_search.set("wrkPathSeq", scwin.params.arrParam[0][4]);
  dma_search.set("wrkStpSeq", scwin.params.arrParam[0][5]);
  dma_search.set("crryoutDt", em_wrkStDt.getValue());
  dma_search.set("crryinDt", em_wrkEndDt.getValue());
  dma_search.set("cntrNo", em_cntrNo.getValue());
  dma_search.set("dptWrkPlCd", em_dptWrkPlCd.getValue());
  dma_search.set("arvWrkPlCd", em_arvWrkPlCd.getValue());
  dma_search.set("crryoutEdiType", scwin.gv_crryoutEdiType);
  dma_search.set("crryinEdiType", scwin.gv_crryinEdiType);
  dma_search.set("vehclNo", scwin.params.arrParam[0][7]);
  dma_search.set("vehclIdCardNo", scwin.params.arrParam[0][8]);

  //console.log("##### scwin.params.arr1 : "+JSON.stringify(scwin.params.arr1)+" :: "+scwin.params.arr1.constructor+" :: "+Object.keys(scwin.params.arr1).length);

  //반출입에서 호출하는경우
  if (scwin.params.arrParam[0][0] == "1") {
    if (scwin.params.arrParam[1].length > 0) {
      dma_search.set("transWrkIndictNo", scwin.params.arrParam[1][0]);
      dma_search.set("vehclNo", scwin.params.arrParam[1][1]);
      dma_search.set("vehclIdCardNo", scwin.params.arrParam[1][2]);
      dma_search.set("drvNm", scwin.params.arrParam[1][3]);
      dma_search.set("cntctPl", scwin.params.arrParam[1][4]);
      dma_search.set("crryoutDt", scwin.params.arrParam[1][5]);
      dma_search.set("crryoutHh", scwin.params.arrParam[1][6]);
      dma_search.set("crryinDt", scwin.params.arrParam[1][7]);
      dma_search.set("crryinHh", scwin.params.arrParam[1][8]);
      dma_search.set("vehclShortCd", scwin.params.arrParam[1][9]);
      dma_search.set("eqCd", scwin.params.arrParam[1][10]);
    }
  }
  console.log("##### scwin.f_Retrieve");
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  //console.log("##### sbm_retrieve_submitdone : "+JSON.stringify(e));
  if (e.responseJSON.resultDataSet[0].Code < 0) return;
  if (scwin.param_gubun == "NO") {
    $c.gus.cfDisableObjects($p, [em_cntrNo, em_cntrNo2]);
  }
};

