scwin.f_validate = async function () {
  //반출(COPINO)
  if (chk_crryOutCopino.getValue() == "T") {
    if (!(await $c.gus.cfValidate($p, [tb_crryOutCopino], null, true))) {
      return false;
    }

    //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
    if (dma_resultsCopino1.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && dma_resultsCopino1.get("vehclIdCardNo") == "") {
      await $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
      return false;
    }

    //[full/empty구분=full]이면 SEAL NO를 입력받아야함
    if (dma_resultsCopino1.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && dma_resultsCopino1.get("sealNo") == "") {
      await $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
      return false;
    }

    // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    // $c.gus.cfCopyDataSet(dma_resultsCopino1, ds_resultsCopino3, v_features);
    ds_resultsCopino3.insertRow();
    ds_resultsCopino3.setRowJSON(0, dma_resultsCopino1.getJSON());
  }

  //반입(COPINO)
  if (chk_crryInCopino.getValue() == "T") {
    if (!(await $c.gus.cfValidate($p, [tb_crryInCopino], null, true))) {
      return false;
    }
    if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && (dma_resultsCopino2.get("totWt") == 0 || dma_resultsCopino2.get("totWt") == "")) {
      await $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [WEIGHT]는 필수입니다");
      return false;
    }

    //[사전정보그룹구분=터미널]이면 차량ID를 입력받아야함
    if (dma_resultsCopino2.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && dma_resultsCopino2.get("vehclIdCardNo") == "") {
      await $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [차량ID카드번호]는 필수입니다");
      return false;
    }

    //[사전정보그룹구분=터미널]이면 모선/항차를 입력받아야함
    if (dma_resultsCopino2.get("preInfoGrpClsCd") == DsConstants.EDI_GRPCD_TM && dma_resultsCopino2.get("tmlVsslPortcnt") == "") {
      await $c.gus.cfAlertMsg($p, "[사전정보그룹구분]이 터미널 일때 [모선/항차]는 필수입니다");
      return false;
    }

    //[full/empty구분=full]이면 SEAL NO를 입력받아야함
    if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && dma_resultsCopino2.get("sealNo") == "") {
      await $c.gus.cfAlertMsg($p, "[E/F 구분]이 FULL 일때 [SEAL NO]는 필수입니다");
      return false;
    }

    //[full/empty구분=full]이고 SIZE/TYPE이 RF,RH 이면 냉동온도를 입력받아야함
    if (dma_resultsCopino2.get("fullEmptyClsCd") == DsConstants.EDI_FULL_EMPTY_CLS_FULL && em_frzTemper2.getValue() == "" && (dma_resultsCopino2.get("sizTyp") == "2232" || dma_resultsCopino2.get("sizTyp") == "4332" || dma_resultsCopino2.get("sizTyp") == "4337" || dma_resultsCopino2.get("sizTyp") == "4532")) {
      if (!(await $c.win.confirm($p, "냉동컨테이너에 온도가 입력되지 않았습니다.\n그래도 계속 진행하시겠습니까?"))) {
        return false;
      }
    }

    // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    // $c.gus.cfCopyDataSet(dma_resultsCopino2, ds_resultsCopino4, v_features);
    ds_resultsCopino4.insertRow();
    ds_resultsCopino4.setRowJSON(0, dma_resultsCopino2.getJSON());

    //PCY     
    if (scwin.param_gubun == "NO") {
      if (dma_resultsCopino2.get("bookingNo") == "" && dma_resultsCopino2.get("blNo") == "") {
        await $c.gus.cfAlertMsg($p, "수입은 B/L번호 , 수출은 BOOKING번호  필수입니다!!");
        return false;
      }
    }
  }

  // 반출(COPI_CODECO)
  if (chk_crryOutCopiCodeco.getValue() == "T") {
    if (!(await $c.gus.cfValidate($p, [tb_crryOutCopiCodeco], null, true))) {
      return false;
    }

    //대한통운 일경우 컨테이너번호 필수
    if (dma_resultsCopiCodeco1.get("cls") == "DT") {
      if ($c.gus.cfIsNull($p, dma_resultsCopiCodeco1.get("cntrNo"))) {
        await $c.gus.cfAlertMsg($p, "작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
        return false;
      }
    }

    // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    // $c.gus.cfCopyDataSet(ds_resultsCopiCodeco1, ds_resultsCopiCodeco3, v_features);

    // dma_resultsCopino1.setJSON(ds_resultsCopiCodeco3.getRowJSON(1));
    ds_resultsCopiCodeco3.insertRow();
    ds_resultsCopiCodeco3.setRowJSON(0, dma_resultsCopiCodeco3.getJSON());
  }

  //반입(COPI_CODECO)
  if (chk_crryInCopiCodeco.getValue() == "T") {
    if (!(await $c.gus.cfValidate($p, [tb_crryInCopiCodeco], null, true))) {
      return false;
    }

    //대한통운 일경우 컨테이너번호 필수
    if (dma_resultsCopiCodeco2.get("cls") == "DT") {
      if ($c.gus.cfIsNull($p, dma_resultsCopiCodeco2.get("cntrNo"))) {
        await $c.gus.cfAlertMsg($p, "작업지역이 [대한통운] 일경우 [컨테이너번호]는 필수 입니다.");
        return false;
      }
    }

    // var v_features = "copyHeader=yes,rowFrom=1,rowCnt=1";
    // $c.gus.cfCopyDataSet(ds_resultsCopiCodeco2, ds_resultsCopiCodeco4, v_features);
    ds_resultsCopiCodeco4.insertRow();
    ds_resultsCopiCodeco4.setRowJSON(0, dma_resultsCopiCodeco2.getJSON());
  }
  return true;
};

