scwin.f_resultPopEd = function (rtnList, strCd, strNm) {
  if (rtnList != null) {
    if (rtnList[0] == "N/A") return;
    strCd.setValue(rtnList[2]); // 코드
    strNm.setValue(rtnList[3]); // 명
    strCd.options.hidVal = rtnList[2]; // 히든값
  } else {
    strCd.setValue("");
    strNm.setValue("");
    strCd.options.hidVal = "";
  }
};

